// Dynamic lastRunTime via static data instead of hardcoded date
const staticData = $getWorkflowStaticData('global');
const now = new Date().toISOString();

// First run default: 7 days ago to avoid processing entire historical backlog
const fallback = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString();
const lastRunTime = staticData.lastRunTime || fallback;

// Store as pendingRunTime - only committed to lastRunTime after successful completion
// This prevents missing leads if the workflow fails mid-run
staticData.pendingRunTime = now;

return [{
  json: {
    lastRunTime,
    currentRunTime: now
  }
}];

// Extracts domain AND preserves all original SF lead fields for downstream reference
const email = $json.Email?.toLowerCase() || '';
const domain = email.includes('@') ? email.split('@')[1] : null;

return {
  json: {
    ...$json,
    account_domain: domain
  }
};

const tidyJson = (data) => {
  if (typeof data === 'string') {
    try { return JSON.parse(data); } catch (e) { return {}; }
  }
  return data || {};
};

const user = $input.item.json;

return {
  user_id: user.user_id,
  user_name: user.user_name,
  is_anonymous: user.is_anonymous,
  user_properties: tidyJson(user.user_properties),
  activities_count: user.user_activities ? user.user_activities.length : 0,
  activities: (user.user_activities || []).map(activity => ({
    name: activity.display_name,
    time: activity.timestamp ? new Date(activity.timestamp * 1000).toISOString() : null,
    props: tidyJson(activity.properties)
  })),
  last_event: user.user_last_event_at
};

function findEmail(obj) {
  if (!obj) return null;
  if (typeof obj === 'string') {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (emailRegex.test(obj)) return obj;
  }
  if (typeof obj === 'object') {
    for (const key in obj) {
      const result = findEmail(obj[key]);
      if (result) return result;
    }
  }
  return null;
}

const email = findEmail($json);
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const isValid = email ? emailRegex.test(email) : false;

return {
  json: {
    ...$json,
    emailFound: email,
    validEmail: isValid
  }
};

