(() => {
  const MAX_CHARS = 30000;
  const items = $('Locate Email in Data').item.json.activities || [];
  const blocks = [];

  for (const a of items) {
    const lines = [];
    const name = a.name ?? '';
    const raw = a.time ?? '';
    const time = raw.replace('T', ' T ');
    lines.push(`• ${name} @ ${time}`);

    if (a.props) {
      const channel     = a.props.$channel ?? a.props.channel;
      const pageUrl     = a.props.$page_url ?? a.props.$referrer_url;
      const initialPage = a.props.$initial_page_url;
      const initialRef  = a.props.$initial_referrer_url;
      const pageCount   = a.props.$page_count ?? a.props.page_count;
      const sessionTime = a.props.$session_spent_time ?? a.props.session_spent_time;

      if (channel)     lines.push(`   - Channel: ${channel}`);
      if (initialPage) lines.push(`   - Initial Page: ${initialPage}`);
      if (initialRef)  lines.push(`   - Initial Referrer: ${initialRef}`);
      if (pageUrl)     lines.push(`   - Last URL: ${pageUrl}`);
      if (pageCount !== undefined && pageCount !== '')
        lines.push(`   - Page Count: ${pageCount}`);
      if (sessionTime !== undefined && sessionTime !== '')
        lines.push(`   - Session Spent (s): ${sessionTime}`);
    }
    blocks.push(lines.join('\n'));
  }

  blocks.reverse();
  let output = '';
  for (const block of blocks) {
    if ((output + block + '\n\n').length > MAX_CHARS) break;
    output += block + '\n\n';
  }
  return output.trim();
})()
}}

