// Commit lastRunTime only after all leads have been successfully processed
const staticData = $getWorkflowStaticData('global');
if (staticData.pendingRunTime) {
  staticData.lastRunTime = staticData.pendingRunTime;
  delete staticData.pendingRunTime;
}
return [{ json: { status: 'Workflow completed successfully', lastRunTime: staticData.lastRunTime } }];
